#define BLOCK_SIZE 16

__kernel void hotspot(
    int iter,
    __global const float *power,
    __global const float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float amb_temp = 80.0f;

    int blockId_x = get_group_id(0);
    int blockId_y = get_group_id(1);
    int local_x = get_local_id(0);
    int local_y = get_local_id(1);

    int c_start = blockId_x * BLOCK_SIZE;
    int r_start = blockId_y * BLOCK_SIZE;

    int c_end = c_start + BLOCK_SIZE > col ? col : c_start + BLOCK_SIZE;
    int r_end = r_start + BLOCK_SIZE > row ? row : r_start + BLOCK_SIZE;

    for (int ly = 0; ly < BLOCK_SIZE; ly++) {
        for (int lx = 0; lx < BLOCK_SIZE; lx++) {
            int r = r_start + ly;
            int c = c_start + lx;

            if (r >= r_end || c >= c_end) continue;

            float delta;
            int idx = r * col + c;

            bool is_boundary = (r_start == 0 || c_start == 0 || r_end == row || c_end == col);

            if (is_boundary) {
                if (r == 0 && c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (temp[idx + col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == 0 && c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (temp[idx + col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == row - 1 && c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (temp[idx - col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == row - 1 && c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (temp[idx - col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (temp[idx + col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == row - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (temp[idx - col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
            } else {
                delta = Cap_1 * (power[idx] +
                    (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                    (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                    (amb_temp - temp[idx]) * Rz_1);
            }

            result[idx] = temp[idx] + delta;
        }
    }
}
